class Animal {
  public void eat() {
    System.out.println("Crunch crunch!");
  }
}

// Dog "is an" Animal. It inherits eat() for free!
class Dog extends Animal {
  // Look, no code here!
}

class Main {
  public static void main(String[] args) {
    Dog myDog = new Dog();
    myDog.eat(); // Calls the inherited method
  }
}
